changeSet.sql:
CREATE TABLE IF NOT EXISTS role ( id integer NOT NULL , description character varying(255), name character varying(255) NOT NULL, CONSTRAINT role_pkey PRIMARY KEY (id) );
CREATE SEQUENCE IF NOT EXISTS role_id_seq INCREMENT 1 START 1 NO MINVALUE NO MAXVALUE CACHE 1 OWNED BY role.id;
INSERT INTO role( id, name ,description) VALUES (nextval('role_id_seq'), 'ROLE_ADMIN','Role administrator');
INSERT INTO role( id, name ,description) VALUES (nextval('role_id_seq'), 'ROLE_USER','Role user');
